  const handleForm856Change = (newData: FormData856) => {
    setFormData856(newData);
    const newEdi = build856(newData);
    setRawEdi(newEdi);
    processEdi(newEdi, false);
  };

  const handleFieldFocus = (fieldId: string) => {
      // 1. Visual Highlight
      setHighlightedField(fieldId);
      setTimeout(() => setHighlightedField(null), 2000);

      const el = document.getElementById(fieldId);
      if (el) {
          el.scrollIntoView({ behavior: 'smooth', block: 'center' });
      }

      // 2. Reverse Highlight: Select Segment
      if (!doc) return;
      const flat = flattenTree(doc.segments);

      let searchStart = 0;
      if (selectedRecordId) {
          const recIdx = records.findIndex(r => r.id === selectedRecordId);
          if (recIdx !== -1) searchStart = records[recIdx].startIndex;
      }

      // --- Enhanced Heuristics ---

      // 1. Line Items (line-X-field)
      const lineMatch = fieldId.match(/^line-(\d+)-/);
      if (lineMatch) {
          const lineIdx = parseInt(lineMatch[1]);
          let currentLineCount = -1;
          for (let i = searchStart; i < flat.length; i++) {
              const s = flat[i];
              // Boundary check to keep within record
              if (i > searchStart && (s.tag === 'ST' || s.tag === 'SE' || s.tag === 'CLM' || s.tag === 'INS')) {
                   if (!fieldId.includes('claim') && !fieldId.includes('subscriber')) break; 
              }

              if (['SV1', 'SV2', 'SV3', 'PO1', 'IT1', 'LIN'].includes(s.tag)) {
                  currentLineCount++;
                  if (currentLineCount === lineIdx) {
                      if (fieldId.includes('Date')) {
                          // Look ahead for DTP
                          const dtp = flat.slice(i, i+5).find(seg => seg.tag === 'DTP' || seg.tag === 'DTM');
                          if (dtp) { setSelectedSegment(dtp); return; }
                      }
                      setSelectedSegment(s);
                      return;
                  }
              }
          }
          return;
      }

      // 2. Dependents (dep-X-field)
      const depMatch = fieldId.match(/^dep-(\d+)-/);
      if (depMatch) {
          const depIdx = parseInt(depMatch[1]);
          let currentDepCount = -1;
          for (let i = searchStart; i < flat.length; i++) {
              const s = flat[i];
              // Detect dependent block start
              let isDepStart = false;
              if (s.tag === 'INS' && s.elements[0]?.value === 'N') isDepStart = true;
              else if (s.tag === 'HL' && s.elements[2]?.value === '23') isDepStart = true;
              else if (s.tag === 'NM1' && s.elements[0]?.value === '03') isDepStart = true;

              if (isDepStart) {
                  // Only count distinct loop starts
                  if (s.tag === 'NM1' && s.elements[0]?.value === '03') currentDepCount++;
                  else if (s.tag === 'INS' && s.elements[0]?.value === 'N') currentDepCount++;
                  // HL might be parent of NM1, avoid double count if possible, or rely on NM1 match primarily

                  if (currentDepCount === depIdx) {
                      if (fieldId.includes('firstName') || fieldId.includes('lastName')) {
                          if (s.tag === 'NM1') { setSelectedSegment(s); return; }
                          // For 834, dependent names can be NM1*IL inside the dependent loop (standard 2100A), or NM1*03/QC
                          const nm1 = flat.slice(i, i+10).find(seg => seg.tag === 'NM1' && (seg.elements[0]?.value === '03' || seg.elements[0]?.value === 'QC' || seg.elements[0]?.value === 'IL'));
                          if (nm1) { setSelectedSegment(nm1); return; }
                      }
                      if (fieldId.includes('dob') || fieldId.includes('gender')) {
                          const dmg = flat.slice(i, i+10).find(seg => seg.tag === 'DMG');
                          if (dmg) { setSelectedSegment(dmg); return; }
                      }
                      setSelectedSegment(s);
                      return;
                  }
              }
          }
          return;
      }

      // 3. Static Field Mapping
      let tag = '', el1Codes: string[] | undefined = undefined;
      let lookAheadFor = '';

      if (fieldId === 'payerName') { tag = 'NM1'; el1Codes = ['PR', '41', 'IN', '40']; }
      else if (fieldId === 'payerId') { tag = 'NM1'; el1Codes = ['PR', '41', 'IN']; }
      else if (fieldId === 'providerName') { tag = 'NM1'; el1Codes = ['1P', '85', 'PE', 'FA']; }
      else if (fieldId === 'providerNpi') { tag = 'NM1'; el1Codes = ['1P', '85', 'PE']; }

      // Subscriber Mappings
      else if (fieldId === 'subscriberFirstName' || fieldId === 'subFirstName') { tag = 'NM1'; el1Codes = ['IL', '74']; }
      else if (fieldId === 'subscriberLastName' || fieldId === 'subLastName') { tag = 'NM1'; el1Codes = ['IL', '74']; }
      else if (fieldId === 'subscriberId' || fieldId === 'subId') { tag = 'NM1'; el1Codes = ['IL']; } 
      else if (fieldId === 'subSsn') { tag = 'REF'; el1Codes = ['SY']; }
      else if (fieldId === 'subDob') { tag = 'DMG'; }
      else if (fieldId === 'subGender') { tag = 'DMG'; }

      // 834 Specific
      else if (fieldId === 'sponsorName') { tag = 'N1'; el1Codes = ['P5']; }
      else if (fieldId === 'sponsorTaxId') { tag = 'N1'; el1Codes = ['P5']; }
      else if (fieldId === 'maintenanceType') { tag = 'INS'; }
      else if (fieldId === 'maintenanceReason') { tag = 'INS'; }
      else if (fieldId === 'policyNumber') { tag = 'REF'; el1Codes = ['1L']; }
      else if (fieldId === 'coverageLevelCode') { tag = 'HD'; }
      else if (fieldId === 'planEffectiveDate') { tag = 'DTP'; el1Codes = ['348', '356']; }

      // 837 Specific
      else if (fieldId === 'billingProviderName') { tag = 'NM1'; el1Codes = ['85']; }
      else if (fieldId === 'billingProviderAddress') { tag = 'NM1'; el1Codes = ['85']; lookAheadFor = 'N3'; }
      else if (fieldId === 'billingProviderCity') { tag = 'NM1'; el1Codes = ['85']; lookAheadFor = 'N4'; }
      else if (fieldId === 'billingTaxId') { tag = 'REF'; el1Codes = ['EI']; }
      else if (fieldId === 'claimId') { tag = 'CLM'; }
      else if (fieldId === 'totalCharge') { tag = 'CLM'; }

      // Other
      else if (fieldId === 'serviceDate') { tag = 'DTP'; el1Codes = ['472', '291']; }
      else if (fieldId === 'poNumber') { tag = 'BEG'; }
      else if (fieldId === 'invoiceNumber') { tag = 'BIG'; }
      else if (fieldId === 'shipmentId') { tag = 'BSN'; }
      else if (fieldId === 'shipToName') { tag = 'NM1'; el1Codes = ['ST']; }
      else if (fieldId === 'shipToAddress') { tag = 'NM1'; el1Codes = ['ST']; lookAheadFor = 'N3'; }
      else if (fieldId === 'shipToCity') { tag = 'NM1'; el1Codes = ['ST']; lookAheadFor = 'N4'; }
      else if (fieldId === 'sellerName') { tag = 'NM1'; el1Codes = ['SE']; }
      else if (fieldId === 'buyerName') { tag = 'NM1'; el1Codes = ['BY']; }

      if (tag) {
          for (let i = searchStart; i < flat.length; i++) {
              const s = flat[i];
              if (s.tag === tag) {
                  if (!el1Codes || (s.elements[0]?.value && el1Codes.includes(s.elements[0]?.value))) {
                      if (lookAheadFor) {
                          const target = flat.slice(i, i+5).find(sub => sub.tag === lookAheadFor);
                          if (target) { setSelectedSegment(target); return; }
                      } else {
                          setSelectedSegment(s);
                          return;
                      }
                  }
              }
          }
      }
  };

  const handleSegmentSelect = (segment: EdiSegment) => {
      setSelectedSegment(segment);
      if (!doc) return;

      const flat = flattenTree(doc.segments);
      const index = flat.findIndex(s => s.id === segment.id);
      if (index === -1) return;

      let fieldId = null;
      const tag = segment.tag;
      const val = (i: number) => segment.elements[i]?.value;

      // Identify context (Parent Loop)
      let contextEntity = 'Unknown'; 
      for (let i = index; i >= 0; i--) {
          const s = flat[i];
          if (s.tag === 'NM1') {
              const q = s.elements[0]?.value;
              if (q === '85') { contextEntity = 'BillingProvider'; break; }
              if (q === 'IL' || q === '74') { contextEntity = 'Subscriber'; break; }
              if (q === '03' || q === 'QC') { contextEntity = 'Dependent'; break; }
              if (q === 'PR' || q === '41' || q === '40') { contextEntity = 'Payer'; break; }
              if (q === '1P') { contextEntity = 'Provider'; break; }
              if (q === 'ST') { contextEntity = 'ShipTo'; break; }
              if (q === 'SE') { contextEntity = 'Seller'; break; }
              if (q === 'BY') { contextEntity = 'Buyer'; break; }
              if (q === 'P5') { contextEntity = 'Sponsor'; break; }
          }
          if (s.tag === 'HL') {
              const lvl = s.elements[2]?.value;
              if (lvl === '20') { contextEntity = 'Payer'; break; }
              if (lvl === '21') { contextEntity = 'Provider'; break; }
              if (lvl === '22') { contextEntity = 'Subscriber'; break; }
              if (lvl === '23') { contextEntity = 'Dependent'; break; }
              if (lvl === '19') { contextEntity = 'Provider'; break; }
          }
          if (s.tag === 'INS') {
              if (s.elements[0]?.value === 'Y') contextEntity = 'Subscriber';
              if (s.elements[0]?.value === 'N') contextEntity = 'Dependent';
          }
      }

      if (tag === 'NM1') {
          const q = val(0);
          if (q === 'PR' || q === '41' || q === '40') fieldId = 'payerName';
          else if (q === '1P') fieldId = 'providerName';
          else if (q === 'IL') {
              if (contextEntity === 'Subscriber') fieldId = 'subFirstName'; // 834
              else if (contextEntity === 'Dependent') fieldId = 'dependentFirstName'; // 834 dep
              else fieldId = 'subscriberFirstName'; // General
          }
          else if (q === '03') fieldId = 'dependentFirstName';
          else if (q === '85') fieldId = 'billingProviderName';
          else if (q === 'BY') fieldId = 'buyerName';
          else if (q === 'SE') fieldId = 'sellerName';
          else if (q === 'ST') fieldId = 'shipToName';
          else if (q === 'P5') fieldId = 'sponsorName';
      }
      else if (tag === 'N3') {
          if (contextEntity === 'BillingProvider') fieldId = 'billingProviderAddress';
          else if (contextEntity === 'ShipTo') fieldId = 'shipToAddress';
      }
      else if (tag === 'N4') {
          if (contextEntity === 'BillingProvider') fieldId = 'billingProviderCity';
          else if (contextEntity === 'ShipTo') fieldId = 'shipToCity';
      }
      else if (tag === 'DMG') {
          if (contextEntity === 'Subscriber') fieldId = 'subDob';
          else if (contextEntity === 'Dependent') fieldId = 'dependentDob';
      }
      else if (tag === 'REF') {
          const q = val(0);
          if (q === 'EI') fieldId = 'billingTaxId';
          if (q === 'SY') fieldId = 'subSsn';
          if (q === '0F' || q === 'MI') fieldId = 'subscriberId'; // or subId
          if (q === '1L') fieldId = 'policyNumber';
          if (q === 'CN' || q === 'BM') fieldId = 'trackingNumber';
      }
      else if (tag === 'CLM') fieldId = 'claimId';
      else if (tag === 'BEG') fieldId = 'poNumber';
      else if (tag === 'BIG') fieldId = 'invoiceNumber';
      else if (tag === 'BSN') fieldId = 'shipmentId';
      else if (tag === 'BPR') fieldId = 'totalPayment';
      else if (tag === 'INS') { fieldId = 'maintenanceType'; }
      else if (tag === 'HD') { fieldId = 'coverageLevelCode'; }
      else if (tag === 'TRN') {
          if (val(0) === '1') fieldId = 'checkNumber';
      }
      else if (tag === 'DTP') {
          const q = val(0);
          if (q === '472' || q === '291') fieldId = 'serviceDate';
          if (q === '348' || q === '356') fieldId = 'planEffectiveDate';
      }
      else if (['SV1', 'SV2', 'SV3', 'PO1', 'IT1', 'LIN'].includes(tag)) {
          // Calculate index relative to current transaction
          let count = 0;
          // Find enclosing ST/SE
          let startBoundary = 0;
          for(let i=index; i>=0; i--) { if(flat[i].tag === 'ST') { startBoundary = i; break; } }

          for (let i = startBoundary; i < index; i++) {
              if (flat[i].tag === tag) count++;
          }
          if (tag.startsWith('SV')) fieldId = `line-${count}-procedureCode`;
          else fieldId = `line-${count}-partNumber`;
      }

      // Handle Dependent Fields (dep-X-field)
      if (contextEntity === 'Dependent') {
          let depCount = -1; // 0-based index
          // Count dependent loops from start of transaction or record
          let startBoundary = 0;
          for(let i=index; i>=0; i--) { if(flat[i].tag === 'ST' || (flat[i].tag === 'INS' && flat[i].elements[0]?.value === 'Y')) { startBoundary = i; break; } }

          for (let i = startBoundary; i <= index; i++) {
              const s = flat[i];
              // Count markers for dependent loops
              if ((s.tag === 'NM1' && s.elements[0]?.value === '03') || (s.tag === 'INS' && s.elements[0]?.value === 'N')) {
                  depCount++;
              }
          }

          // Heuristic correction for double counting if markers are adjacent
          // (Simplified: assuming one marker per loop in standard counting)

          // Renormalize loopCount by checking how many *distinct* loops started
          // For 834, each dependent loop starts with INS*N.
          let loopCount = 0;
          for (let i = startBoundary; i < index; i++) {
               const s = flat[i];
               if (s.tag === 'INS' && s.elements[0]?.value === 'N') loopCount++;
               else if (s.tag === 'NM1' && s.elements[0]?.value === '03') {
                   // Only count if not preceded immediately by INS*N (avoid double count)
                   const prev = flat[i-1];
                   if (!prev || prev.tag !== 'INS') loopCount++;
               }
          }

          if (fieldId === 'dependentFirstName' || fieldId === 'dependentDob') {
               if (fieldId === 'dependentFirstName') fieldId = `dep-${loopCount}-firstName`;
               if (fieldId === 'dependentDob') fieldId = `dep-${loopCount}-dob`;
          } else if (!fieldId && tag === 'NM1') {
               fieldId = `dep-${loopCount}-firstName`;
          }
          // Special case for 834 dependent names mapping to NM1*IL
          else if (tag === 'NM1' && val(0) === 'IL') {
               fieldId = `dep-${loopCount}-firstName`;
          }
      }

      if (fieldId) {
          setHighlightedField(fieldId);
          setTimeout(() => setHighlightedField(null), 2000);
          const el = document.getElementById(fieldId);
          if (el) el.scrollIntoView({ behavior: 'smooth', block: 'center' });
      }
  };

  const startResizing = (e: React.MouseEvent) => {
      e.preventDefault();

      const handleMouseMove = (moveEvent: MouseEvent) => {
          const newWidth = Math.max(400, Math.min(moveEvent.clientX, window.innerWidth * 0.8));
          setSidebarWidth(newWidth);
      };

      const handleMouseUp = () => {
          document.removeEventListener('mousemove', handleMouseMove);
          document.removeEventListener('mouseup', handleMouseUp);
          document.body.style.cursor = 'default';
          document.body.classList.remove('select-none');
      };

      document.addEventListener('mousemove', handleMouseMove);
      document.addEventListener('mouseup', handleMouseUp);
      document.body.style.cursor = 'col-resize';
      document.body.classList.add('select-none');
  };

  return (
    <div className="flex flex-col h-screen bg-white dark:bg-slate-950 text-gray-900 dark:text-slate-200 font-sans overflow-hidden transition-colors">
      <header className="flex-none h-14 bg-white dark:bg-slate-900 border-b border-gray-200 dark:border-slate-800 flex items-center justify-between px-6 z-30">
        <div className="flex items-center space-x-4">
            <button onClick={() => navigate('/')} className="flex items-center space-x-2">
                <div className="w-6 h-6 bg-black dark:bg-brand-500 rounded-sm flex items-center justify-center">
                    <span className="text-white font-mono font-bold text-xs">X12</span>
                </div>
                <span className="font-medium text-sm tracking-tight text-gray-900 dark:text-white uppercase">EDI Insight</span>
            </button>
            {doc?.transactionType && (
                <span className="text-[10px] px-2 py-0.5 rounded-full border border-gray-200 dark:border-slate-700 bg-gray-50 dark:bg-slate-800 text-gray-500 dark:text-slate-400 font-mono">
                    {doc.transactionType}
                </span>
            )}
        </div>

        <nav className="flex items-center gap-1 p-1 bg-gray-100/80 dark:bg-slate-800/80 rounded-lg">
             <NavTab active={viewMode === 'inspector'} onClick={() => setViewMode('inspector')} label="Inspector" icon="🔍" />
             <NavTab active={viewMode === 'visual'} onClick={() => setViewMode('visual')} label="Visual Report" disabled={!doc} icon="📄" />
             <NavTab active={viewMode === 'json'} onClick={() => setViewMode('json')} label="JSON" disabled={!doc} icon="{} " />
             <NavTab active={viewMode === 'raw'} onClick={() => setViewMode('raw')} label="Editor" icon="✏️" />
        </nav>

        <div className="flex items-center gap-3">
             {doc && (
                 <button 
                    onClick={handleClearFile}
                    className="text-xs font-medium text-red-600 dark:text-red-400 hover:bg-red-50 dark:hover:bg-red-900/30 px-3 py-1.5 rounded transition-colors"
                 >
                    New File
                 </button>
             )}
             <button onClick={() => setViewMode('settings')} className="p-1.5 rounded-md hover:bg-gray-100 dark:hover:bg-slate-800 transition-colors">⚙️</button>
        </div>
      </header>

      <div className="flex-1 flex overflow-hidden">
        {doc && ['inspector', 'visual', 'raw', 'json'].includes(viewMode) && (
            <>
                <div className="flex-none bg-white dark:bg-slate-900 border-r border-gray-200 dark:border-slate-800 flex" style={{ width: sidebarWidth }}>
                    <RecordList records={records} selectedId={selectedRecordId} onSelect={handleRecordSelect} onResetAll={() => {}} onResetRecord={() => {}} isModified={false} />
                    <div className="flex-1 overflow-hidden">
                        <EdiGenerator 
                            formData={formData} onChange={handleFormChange}
                            formData276={formData276} onChange276={handleForm276Change}
                            formData837={formData837} onChange837={handleForm837Change}
                            formData834={formData834} onChange834={handleForm834Change}
                            formData278={formData278} onChange278={handleForm278Change}
                            formData820={formData820} onChange820={handleForm820Change}
                            formData850={formData850} onChange850={handleForm850Change}
                            formData810={formData810} onChange810={handleForm810Change}
                            formData856={formData856} onChange856={handleForm856Change}
                            generatorMode={generatorMode} onSetGeneratorMode={m => setGeneratorMode(m)}
                            transactionType={doc.transactionType}
                            benefits={benefits} 
                            claims={claims} 
                            remittanceInfo={remittance?.info}
                            remittanceClaims={remittance?.claims}
                            selectedSegment={selectedSegment} 
                            onFieldFocus={handleFieldFocus}
                            highlightedField={highlightedField}
                        />
                    </div>
                </div>
                {/* Resize Handle */}
                <div
                    className="w-1 bg-transparent hover:bg-brand-500 cursor-col-resize transition-colors z-10 -ml-0.5"
                    onMouseDown={startResizing}
                />
            </>
        )}

        <div className="flex-1 flex min-w-0 bg-white dark:bg-slate-950 relative">

          {viewMode === 'settings' && <Settings />}
          {viewMode === 'reference' && <CodeSearch />}
          {viewMode === 'contact' && <SendMessage />}

          {['inspector', 'visual', 'raw', 'json'].includes(viewMode) && (
              !doc ? (
                <div className="w-full h-full">
                    <DragDropInput onProcess={handleLoadNewEdi} industry={industry} />
                </div>
              ) : (
                <>
                    {viewMode === 'inspector' && (
                        <div className="flex w-full h-full">
                            <div className="w-1/3 min-w-[250px] border-r border-gray-200 dark:border-slate-800 flex flex-col h-full bg-white dark:bg-slate-900">
                                <SegmentTree 
                                    segments={doc.segments} 
                                    selectedId={selectedSegment?.id || null} 
                                    onSelect={handleSegmentSelect} 
                                />
                            </div>
                            <div className="flex-1 bg-white dark:bg-slate-950 h-full overflow-hidden">
                                {selectedSegment ? (
                                    <SegmentDetail segment={selectedSegment} />
                                ) : (
                                    <div className="flex items-center justify-center h-full text-gray-300 dark:text-slate-600 text-sm">Select a segment to view details</div>
                                )}
                            </div>
                        </div>
                    )}
                    {viewMode === 'visual' && <VisualReport doc={doc} selectedRecordId={selectedRecordId} onFieldFocus={handleFieldFocus} />}
                    {viewMode === 'json' && (
                        <div className="flex flex-col h-full bg-white dark:bg-slate-950">
                            <div className="flex items-center gap-2 px-6 py-2 border-b border-gray-100 dark:border-slate-800 bg-gray-50/50 dark:bg-slate-900/50">
                                <button 
                                    onClick={() => setJsonMode('simplified')}
                                    className={`text-xs font-medium px-3 py-1.5 rounded-full transition-colors ${jsonMode === 'simplified' ? 'bg-black dark:bg-white text-white dark:text-black shadow-sm' : 'text-gray-500 hover:bg-gray-200 dark:hover:bg-slate-800'}`}
                                >
                                    Simplified Object
                                </button>
                                <button 
                                    onClick={() => setJsonMode('structure')}
                                    className={`text-xs font-medium px-3 py-1.5 rounded-full transition-colors ${jsonMode === 'structure' ? 'bg-black dark:bg-white text-white dark:text-black shadow-sm' : 'text-gray-500 hover:bg-gray-200 dark:hover:bg-slate-800'}`}
                                >
                                    Raw AST Structure
                                </button>
                            </div>
                            <div className="p-8 flex-1 overflow-y-auto custom-scrollbar">
                                <JsonViewer data={jsonMode === 'simplified' ? activeFormData : doc} initiallyOpen={true} />
                            </div>
                        </div>
                    )}
                    {viewMode === 'raw' && (
                        <textarea 
                            className="flex-1 w-full p-8 bg-white dark:bg-slate-950 text-gray-800 dark:text-slate-200 font-mono text-sm resize-none outline-none leading-relaxed h-full" 
                            value={rawEdi} 
                            onChange={(e) => { setRawEdi(e.target.value); processEdi(e.target.value, true); }} 
                            spellCheck={false} 
                        />
                    )}
                </>
              )
          )}
        </div>
      </div>
      {doc && <ChatInterface rawEdi={rawEdi} />}
    </div>
  );
}

